previewCss:
.darma-loader-darma-custom-086 {
  width: 40px;
  height: 40px;
  display: grid;
  animation: darma-loader-darma-custom-086-l6-0 1.5s infinite linear;
}
.darma-loader-darma-custom-086:before,
.darma-loader-darma-custom-086:after {
  content: "";
  grid-area: 1/1;
  background: var(--loader-color, #514b82);
  animation: 
    darma-loader-darma-custom-086-l6-1 1.5s infinite linear,
    darma-loader-darma-custom-086-l6-2 1.5s infinite linear;
}
.darma-loader-darma-custom-086:after {
  --s:-1;
  animation-direction: reverse;
}
@keyframes darma-loader-darma-custom-086-l6-0 {
  0%,9%,91%,100% {background: var(--loader-color, #514b82)}
  10%,90%        {background: #0000}
}
@keyframes darma-loader-darma-custom-086-l6-1 {
  0%,33%   {clip-path: polygon(0   0,50% 100%,100% 0,100% 100%,0 100%)}
  66%,100% {clip-path: polygon(50% 0,50% 100%,50%  0,100% 100%,0 100%)}
}
@keyframes darma-loader-darma-custom-086-l6-2 {
  0%,10%,90%,100% {transform: scale(var(--s,1)) translateY(0)}
  33%,66%         {transform: scale(var(--s,1)) translateY(50%)}
}

